INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'hostels', 'Hostels > Boys Summary: 8 boys hostels total. BH1 and BH2 are for 1st years with 4-sharing rooms. BH5 is for 1st years with 2-sharing rooms. BH3, BH4, BH6, BH7, and MBH are for senior years with 2-sharing rooms.');
