INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'mess', 'Mess > Cuisine: Predominantly North Indian with Punjabi staples (parathas, chole bhature, dal makhani). Both veg and non-veg options on multiple days. Non-veg chicken served on Monday, Wednesday, Friday, Sunday. Egg options on Saturday.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > Program: B.Tech 1st Year New Admission 2024-2025.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > GEN/OBC (Family Income > Rs 5 Lakhs): Tuition Fee Rs 1,25,000 + Other Charges Rs 31,930 = Total Rs 1,56,930 per year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > GEN/OBC (Family Income Rs 1 to 5 Lakhs): Tuition Fee Rs 41,670 + Other Charges Rs 31,930 = Total Rs 73,600 per year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > GEN/OBC (Family Income < Rs 1 Lakh) & SC/ST/PH: Tuition Fee Rs 0 + Other Charges Rs 31,930 = Total Rs 31,930 per year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > Hostel: Rs 3,000 extra charged if single seater room allotted.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'fee_structure', 'Fee Structure > Note: Economically backward GEN/OBC students must submit family income certificate (issued on or after 1st April of every financial year) before the last date of online reporting to avail tuition fee waiver. Otherwise treated as fee defaulter.');
