INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'academics', 'Academics > Timetable source: CSE+DS Section B2, Session 2025-26 Even Semester, Department of Basic Sciences.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'academics', 'Academics > Subjects: Computer Programming (CP), Discrete Combinatorics & Graph Theory (DC&G), Engineering & Information Sciences (EIS), Environmental Studies (ES), English Communication Lab, Design Thinking/Innovation & Research (DT/IR), Mathematics-I, Mathematics-II.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'academics', 'Academics > Labs: CP Lab (OP B2a), DC Lab (B2a), EC Lab (B2c), English Communication Lab, DTF8 Combined Lab.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'academics', 'Academics > Faculty includes: Swarnima Singh (CP Lab), Harsh Kumar Verma (CP Theory), Somesela Maddy (DC&G), Mandrem Dev (ES Lab), Prashant Ram (ES Lab), Supreethi (DT/IR), Saurabh Kumar Katiyar (Maths).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jalandhar', 'academics', 'Academics > Class timings: Monday to Friday, 8:30 AM to 4:30 PM.');
